import{_ as o,C as n,o as i,c as r,ag as a,E as l,w as s,a as d}from"./chunks/framework.BZohXCq9.js";const A=JSON.parse('{"title":"WhatsApp","description":"Cómo funciona la integración con WhatsApp en SYNTIweb","frontmatter":{"title":"WhatsApp","description":"Cómo funciona la integración con WhatsApp en SYNTIweb"},"headers":[],"relativePath":"studio/whatsapp.md","filePath":"studio/whatsapp.md"}'),p={name:"studio/whatsapp.md"};function c(h,t,u,m,b,g){const e=n("Note");return i(),r("div",null,[t[1]||(t[1]=a('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>WhatsApp es el canal principal de comunicación entre tu negocio y tus clientes en SYNTIweb. No es un chat integrado en la página — es un <strong>botón que abre WhatsApp</strong> directamente con tu número, listo para que el cliente te escriba.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Para configurar tu WhatsApp:</strong></p><ul><li><strong>Tu panel → Tu Información → Negocio</strong> → Campo <strong>&quot;WhatsApp (ventas)&quot;</strong></li><li>Para el segundo número: Campo <strong>&quot;WhatsApp Soporte&quot;</strong> (Plan Crecimiento+)</li></ul><p><strong>En la landing (lo que ve tu cliente):</strong></p><ul><li>Botón flotante de WhatsApp (esquina inferior derecha, siempre visible)</li><li>Botón de WhatsApp en la sección de contacto</li><li>Botones CTA en servicios que enlazan a WhatsApp</li></ul><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Botón flotante</strong> en toda la landing — siempre accesible para el cliente</li><li><strong>Abre WhatsApp Web o la app</strong> con tu número pre-cargado</li><li><strong>Mensaje pre-escrito</strong> (en algunos contextos): &quot;Hola, vi tu negocio en SYNTIweb...&quot;</li><li><strong>Dos líneas de WhatsApp</strong> (Plan Crecimiento+): ventas y soporte separados</li><li>En <strong>SYNTIfood</strong> (plan Anual): el Pedido Rápido envía el pedido completo como mensaje de WhatsApp</li><li>En <strong>SYNTIcat</strong> (plan Semestral+): el carrito envía el pedido con código SC-XXXX por WhatsApp</li></ul><h3 id="formato-del-numero" tabindex="-1">Formato del número <a class="header-anchor" href="#formato-del-numero" aria-label="Permalink to &quot;Formato del número&quot;">​</a></h3><p>El número se guarda en formato internacional sin el <code>+</code>. Ejemplo:</p><ul><li>Venezuela: <code>584141234567</code> (58 + 414 + 1234567)</li><li>El campo acepta mínimo 10 dígitos</li></ul><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No tiene chat integrado en la página — redirige a WhatsApp</li><li>No guarda historial de conversaciones</li><li>No envía mensajes automáticos (broadcast, seguimiento)</li><li>No tiene bot o respuestas automáticas</li><li>No funciona con WhatsApp Business API — usa el WhatsApp personal del dueño</li><li>No valida si el número es realmente de WhatsApp</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><h3 id="syntistudio" tabindex="-1">SYNTIstudio <a class="header-anchor" href="#syntistudio" aria-label="Permalink to &quot;SYNTIstudio&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>WhatsApp ventas</td><td>✅ (1 línea)</td><td>✅</td><td>✅</td></tr><tr><td>WhatsApp soporte</td><td>❌</td><td>✅ (2da línea)</td><td>✅ (ilimitadas)</td></tr><tr><td>Botón flotante</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>CTA a WhatsApp</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="syntifood" tabindex="-1">SYNTIfood <a class="header-anchor" href="#syntifood" aria-label="Permalink to &quot;SYNTIfood&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>WhatsApp ventas</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Pedido Rápido → WhatsApp</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><h3 id="synticat" tabindex="-1">SYNTIcat <a class="header-anchor" href="#synticat" aria-label="Permalink to &quot;SYNTIcat&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>Botón WA directo (por producto)</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Carrito → WhatsApp</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Mini Order SC-XXXX → WhatsApp</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-peluqueria-estilo-unico-en-barinas" tabindex="-1">Caso: Peluquería &quot;Estilo Único&quot; en Barinas <a class="header-anchor" href="#caso-peluqueria-estilo-unico-en-barinas" aria-label="Permalink to &quot;Caso: Peluquería &quot;Estilo Único&quot; en Barinas&quot;">​</a></h3><p>Ana tiene una peluquería con plan Crecimiento:</p><ol><li>Configura WhatsApp ventas: <code>584161234567</code> (su número principal)</li><li>Configura WhatsApp soporte: <code>584241234567</code> (número de la asistente)</li><li>En la landing aparecen dos botones: <ul><li><strong>&quot;Escríbenos&quot;</strong> → abre WhatsApp con el número de ventas</li><li><strong>&quot;Soporte&quot;</strong> → abre WhatsApp con el número de la asistente</li></ul></li></ol><p>Un cliente ve el servicio &quot;Alisado Brasileño&quot; → toca <strong>&quot;Solicitar cita&quot;</strong> → se abre WhatsApp con Ana automáticamente.</p>',26)),l(e,null,{default:s(()=>[...t[0]||(t[0]=[d(" SYNTIweb usa el formato `https://wa.me/NUMERO` para abrir WhatsApp. Funciona en celular (abre la app) y en escritorio (abre WhatsApp Web). ",-1)])]),_:1}),t[2]||(t[2]=a('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/seccion-info.html">Tu Información</a> — Dónde configuras el número de WhatsApp</li><li><a href="/shared/whatsapp.html">WhatsApp (general)</a> — Conceptos generales del canal WhatsApp</li><li><a href="/studio/productos-y-servicios.html">Productos y servicios</a> — Los botones CTA de servicios enlazan a WhatsApp</li></ul>',2))])}const f=o(p,[["render",c]]);export{A as __pageData,f as default};
